module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);
    parameter [1:0] ZERO = 2'b00, ONE = 2'b01;
    reg [1:0] state;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            state <= ZERO;
        else begin
            case (state)
                ZERO: begin
                    if (a == 1)
                        state <= ONE;
                    else
                        state <= ZERO;
                end
                ONE: begin
                    if (a == 0)
                        state <= ZERO;
                    else
                        state <= ONE;
                end
            endcase
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rise <= 0;
            down <= 0;
        end else begin
            if (state == ZERO && a == 1) begin
                rise <= 1;
                down <= 0;
            end else if (state == ONE && a == 0) begin
                rise <= 0;
                down <= 1;
            end else begin
                rise <= 0;
                down <= 0;
            end
        end
    end
endmodule
